external_knowledge:
; In this context, a 'meteorologist' refers to a person who uploads weather data; 
; 'data uploads' refers to the number of weather records each meteorologist has submitted; 
; 'total precipitation', 'average wind speed', and 'weather events count' are calculated for each location and are associated with the meteorologist who uploaded the data.

sql:
SELECT zone_name, average_temp, average_precipitation
FROM climate_zones
WHERE average_precipitation = (
    SELECT MAX(average_precipitation) FROM climate_zones
);

SELECT DISTINCT m.name
FROM meteorologists m
JOIN data_uploads u ON m.meteorologist_id = u.meteorologist_id;
